uint16_t rle_encode_block(uint8_t* in,uint16_t n,uint8_t* out,uint16_t om){
  if(n==0)return 0;
  uint16_t oi=0;
  uint8_t cv=in[0],cc=1;
  for(uint16_t i=1;i<n;i++){
    if(in[i]==cv&&cc<255){cc++;}
    else{
      if(oi+2>om)break;
      out[oi++]=cv;out[oi++]=cc;
      cv=in[i];cc=1;}}
  if(oi+2<=om){out[oi++]=cv;out[oi++]=cc;}
  return oi;
}
